    CREATE TABLE IF NOT EXISTS ai.skill_files (
      id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
      skill_id UUID NOT NULL REFERENCES ai.skills(id) ON DELETE CASCADE,
